import*as React from"react";import{usePlatform}from"../../hooks/usePlatform";import{Platform}from"../../lib/platform";import{Caption}from"../Typography/Caption/Caption";import{Footnote}from"../Typography/Footnote/Footnote";import{Text}from"../Typography/Text/Text";import{Title}from"../Typography/Title/Title";import styles from"./Alert.module.css";const AlertHeader=e=>{return usePlatform()!==Platform.IOS?React.createElement(Title,{className:styles.Alert__header,weight:"2",level:"2",...e}):React.createElement(Title,{className:styles.Alert__header,weight:"1",level:"3",...e})},AlertText=e=>{switch(usePlatform()){case Platform.VKCOM:return React.createElement(Footnote,{className:styles.Alert__text,...e});case Platform.IOS:return React.createElement(Caption,{className:styles.Alert__text,...e});default:return React.createElement(Text,{Component:"span",className:styles.Alert__text,weight:"3",...e})}};export{AlertHeader,AlertText};